package main

import (
	"strconv"
)

func solve(n int64) bool {
	s := strconv.Itoa(n)
	sumDigits := int64(0)
	productDigits := int64(1)
	for _, ch := range s {
		digit := int64(ch - '0')
		sumDigits += digit
		productDigits *= digit
	}
	total := sumDigits + productDigits
	return n%total == 0
}
